for (const post of posts) {
  if (!post.items) continue;

  for (const postItem of post.items) {
    const caption = postItem.caption?.text || '';

    // Carrossel
    if (postItem.media_type === 8 && postItem.carousel_media) {
      postItem.carousel_media.forEach(media => {
        const url = media.image_versions2?.candidates?.[0]?.url;
        if (url) results.push({ json: { image_url: url, caption } });
      });
    }
    // Imagem/V├¡deo
    else if (postItem.image_versions2) {
      const url = postItem.image_versions2.candidates?.[0]?.url;
      if (url) results.push({ json: { image_url: url, caption } });
    }
  }
}

return results;

