// Extract values
const valueCents = parseInt(paymentData.value_cents) || 0;
const serviceValueCents = parseInt(paymentData.service_value_cents) || valueCents;
const passOnFees = paymentData.pass_on_fees === true;
const feePercent = parseFloat(feeConfig?.fee_percent) || 0;
const feeFixedCents = parseFloat(feeConfig?.fee_fixed) || 0;

// Determine payment method and balance status
// CREDIT_CARD/DEBIT_CARD ÔåÆ 'pending' (aguarda 32 dias)
// PIX/BOLETO ÔåÆ 'success' (dispon├¡vel imediato)
const paymentMethod = paymentData.payment_method || eventData.billing_type || 'PIX';
const isCardPayment = paymentMethod === 'CREDIT_CARD' || paymentMethod === 'DEBIT_CARD';
const balanceStatus = isCardPayment ? 'pending' : 'success';

// Calculate net amount based on fee configuration
let netAmountCents;
let finalFeeCents = 0;

if (passOnFees) {
  // Taxa repassada ao cliente ÔåÆ fot├│grafo recebe o VALOR DO SERVI├çO
  // A taxa j├í foi paga pelo cliente no checkout
  netAmountCents = serviceValueCents;
  finalFeeCents = 0;
} else {
  // Taxa absorvida pelo fot├│grafo ÔåÆ calcula taxa sobre o que cliente pagou
  const calculatedFeeCents = Math.round((valueCents * feePercent / 100) + feeFixedCents);
  finalFeeCents = calculatedFeeCents;
  netAmountCents = valueCents - calculatedFeeCents;
}

// Ensure non-negative
if (netAmountCents < 0) {
  console.error('Negative net amount calculated:', {
    valueCents,
    serviceValueCents,
    passOnFees,
    netAmountCents
  });
  netAmountCents = 0;
}

// Determine new status based on event type
let newPaymentStatus = 'received';
let shouldUpdateAppointment = false;

switch(eventData.event_type) {
  case 'PAYMENT_RECEIVED':
    newPaymentStatus = 'received';
    shouldUpdateAppointment = true;
    break;
  case 'PAYMENT_CONFIRMED':
    newPaymentStatus = 'confirmed';
    shouldUpdateAppointment = true;
    break;
  case 'RECEIVABLE_ANTICIPATION_CREDITED':
    newPaymentStatus = 'anticipated';
    shouldUpdateAppointment = false;
    break;
}

return {
  json: {
    // Payment identifiers
    payment_id: paymentData.payment_id,
    asaas_payment_id: paymentData.asaas_payment_id,
    appointment_id: paymentData.appointment_id,
    user_id: paymentData.user_id,
    client_id: paymentData.client_id,

    // Financial calculations
    value_cents: valueCents,
    service_value_cents: serviceValueCents,
    fee_cents: finalFeeCents,
    net_amount_cents: netAmountCents,
    pass_on_fees: passOnFees,

    // Fee configuration used
    fee_percent: feePercent,
    fee_fixed: feeFixedCents,

    // Balance status for deposits
    // 'pending' = cart├úo aguardando 32 dias
    // 'success' = PIX/boleto dispon├¡vel imediato
    balance_status: balanceStatus,
    payment_method: paymentMethod,

    // Status updates
    new_payment_status: newPaymentStatus,
    should_update_appointment: shouldUpdateAppointment,

    // Event tracking
    event_id: eventData.event_id,
    event_type: eventData.event_type,
    billing_type: eventData.billing_type,

    // Metadata
    calculated_at: new Date().toISOString()
  }
};

