const body = $json.body || $json;
const vars = body.variaveis || {};

// Normalizar todas as vari├íveis para 3 formatos de case
const normalizedVars = {};
for (const [key, value] of Object.entries(vars)) {
  const val = String(value ?? '');
  normalizedVars[key] = val;
  normalizedVars[key.toUpperCase()] = val;
  normalizedVars[key.toLowerCase()] = val;
  // Formato Title_Case (primeira letra mai├║scula de cada palavra)
  const titleCase = key.toLowerCase().replace(/(^|_)([a-z])/g, (m, sep, c) => sep + c.toUpperCase());
  normalizedVars[titleCase] = val;
}

// Sanitizar nome do contrato para uso como filename
const contratoNome = (body.contrato_nome || 'CONTRATO')
  .replace(/[^a-zA-Z0-9├Ç-├┐\s\-_]/g, '')
  .substring(0, 100);

return [{
  json: {
    docx_url: (body.docx_url || '').trim(),
    contrato_nome: contratoNome,
    variaveis: normalizedVars,
    ensaio_id: body.ensaio_id || null,
    callback_url: body.callback_url || null,
    contrato_id: body.contrato_id || null,
    variaveis_definidas: body.variaveis_definidas || [],
    usuario: body.usuario || {}
  }
}];

