const vars = $node['Normalizar Entrada'].json.variaveis || {};
const definedVars = $node['Normalizar Entrada'].json.variaveis_definidas || [];

const requests = [];
const processedKeys = new Set();

// Combinar chaves das vari├íveis enviadas + definidas no template
const allKeys = [...new Set([...Object.keys(vars), ...definedVars])];

for (const key of allKeys) {
  // Evitar duplicatas
  const upperKey = key.toUpperCase();
  if (processedKeys.has(upperKey)) continue;
  processedKeys.add(upperKey);

  // Buscar valor em qualquer case
  const value = vars[key] ?? vars[upperKey] ?? vars[key.toLowerCase()] ?? '';
  const safeValue = String(value);

  // Gerar todas as varia├º├Áes de case da chave
  const keyVariations = [
    key,
    key.toUpperCase(),
    key.toLowerCase(),
    key.toLowerCase().replace(/(^|_)([a-z])/g, (m, s, c) => s + c.toUpperCase())
  ];
  const uniqueVariations = [...new Set(keyVariations)];

  for (const variant of uniqueVariations) {
    // Formato {{chave}}
    requests.push({
      replaceAllText: {
        containsText: { text: '{{' + variant + '}}', matchCase: false },
        replaceText: safeValue
      }
    });
    // Formato {chave}
    requests.push({
      replaceAllText: {
        containsText: { text: '{' + variant + '}', matchCase: false },
        replaceText: safeValue
      }
    });
    // Formato <<chave>>
    requests.push({
      replaceAllText: {
        containsText: { text: '<<' + variant + '>>', matchCase: false },
        replaceText: safeValue
      }
    });
  }
}

return [{ json: { docId, uploadedFileId, requests, totalRequests: requests.length } }];

