  // Formato Title_Case (primeira letra mai├║scula de cada palavra)
  const titleCase = key.toLowerCase().replace(/(^|_)([a-z])/g, (m, sep, c) => sep + c.toUpperCase());
  normalizedVars[titleCase] = val;
}

