const body = $json.body || $json;

// Esperado no body:
// - docx_url: string (signed url do supabase)
// - contrato_nome: string
// - variaveis: objeto { chave: valor }
// - drive_folder_id (opcional): pasta do Drive

const docx_url = (body.docx_url || '').trim();
const contrato_nome = body.contrato_nome || 'CONTRATO';
const variaveis = body.variaveis || body.vars || {};
const drive_folder_id = body.drive_folder_id || body.parent_folder_id || '';

// Se docx_url for signed url do supabase, extrai bucket e path para baixar via Service Role (recomendado)
let bucket = '';
let path = '';
let objectUrl = '';
let useServiceRole = false;

try {
  // Ex: https://<project>.supabase.co/storage/v1/object/sign/contratos/<PATH>?token=...
  const mBucket = docx_url.match(/\/storage\/v1\/object\/sign\/([^/]+)\//);
  const mPath = docx_url.match(/\/storage\/v1\/object\/sign\/[^/]+\/(.+?)\?token=/);
  if (mBucket && mPath) {
    bucket = mBucket[1];
    path = mPath[1];
    const projectUrl = ($env.SUPABASE_PROJECT_URL || '').replace(/\/$/, '');
    if (projectUrl && $env.SUPABASE_SERVICE_ROLE_KEY) {
      objectUrl = `${projectUrl}/storage/v1/object/${bucket}/${path}`;
      useServiceRole = true;
    }
  }
} catch (e) {}

return [{
  json: {
    docx_url,
    contrato_nome,
    variaveis,
    drive_folder_id,
    useServiceRole,
    objectUrl,
    bucket,
    path
  }
}];

const docId = $json.id;
const vars = $node['Normalize Input'].json.variaveis || {};

// Template deve ter placeholders tipo: {{nome_cliente}}
// Cada chave do objeto vira um replaceAllText
const requests = Object.entries(vars).map(([k, v]) => ({
  replaceAllText: {
    containsText: {
      text: `{{${k}}}`,
      matchCase: true
    },
    replaceText: String(v ?? '')
  }
}));

return [{ json: { docId, requests } }];

if (!$binary || !$binary.data) {
  throw new Error('Binary "data" n├úo encontrado');
}

// Ô£à AQUI est├í o base64 REAL
const base64 = $binary.data.data;

if (!base64) {
  throw new Error('Binary existe, mas data est├í vazia');
}

return [
  {
    json: {
      number: ($json.number || $json.whatsapp || '').replace(/\D/g, ''),
      fileName: `CONTRATO_${Date.now()}.pdf`,
      caption: 'Segue seu contrato em PDF.',
      // ÔÜá´©Å Evolution exige prefixo data:
      mediaBase64: `data:application/pdf;base64,${base64}`,
      instance: $json.instance || 'SUA_INSTANCIA_AQUI'
    }
  }
];

// Processar cada lembrete para WUZAPI
const items = $input.all();
const results = [];

for (const item of items) {
  const reminder = item.json;

  // Substituir placeholders no template
  let message = reminder.template || '';

  // Placeholders dispon├¡veis
  const replacements = {
    '{cliente_nome}': reminder.cliente_nome || 'Cliente',
    '{gallery_nome}': reminder.gallery_nome || 'Galeria',
    '{gallery_link}': reminder.gallery_link || '',
    '{senha}': reminder.senha || '',
    '{expires_at}': reminder.expires_at ? new Date(reminder.expires_at).toLocaleDateString('pt-BR') : ''
  };

  // Aplicar substitui├º├Áes
  for (const [placeholder, value] of Object.entries(replacements)) {
    message = message.split(placeholder).join(value);
  }

  // Formatar telefone para formato WUZAPI (sem + na frente)
  // WUZAPI requer: pa├¡s + DDD + n├║mero (ex: 5521971532700)
  let phone = (reminder.cliente_telefone || '').replace(/\D/g, '');

  // Adicionar c├│digo do pa├¡s se n├úo tiver (10-11 d├¡gitos = Brasil sem c├│digo)
  if (phone.length === 10 || phone.length === 11) {
    phone = '55' + phone;
  }

  // Remover + se existir (WUZAPI n├úo aceita)
  phone = phone.replace(/^\+/, '');

  results.push({
    json: {
      id: reminder.id,
      user_id: reminder.user_id,
      phone: phone,
      message: message,
      base_url: reminder.base_url,
      instance_name: reminder.instance_name,
      api_key: reminder.api_key,  // Usado como 'token' no header WUZAPI
      instance_id: reminder.instance_id,
      attempts: parseInt(reminder.attempts) || 0,
      cliente_nome: reminder.cliente_nome,
      gallery_nome: reminder.gallery_nome
    }
  });
}

return results;

// Verificar tentativas e decidir: retry ou failed
const item = $input.item.json;
const attempts = parseInt($('Processar Template').item.json.attempts) || 0;
const reminderId = $('Processar Template').item.json.id;

// Extrair mensagem de erro do WUZAPI
let errorMessage = 'Erro desconhecido';
if (item.body?.error) {
  errorMessage = item.body.error;
} else if (item.body?.data) {
  errorMessage = JSON.stringify(item.body.data);
} else if (item.error?.message) {
  errorMessage = item.error.message;
}

if (attempts < 3) {
  // Reagendar para +5 minutos
  return {
    json: {
      id: reminderId,
      action: 'retry',
      attempts: attempts + 1,
      error_message: `${errorMessage} (tentativa ${attempts + 1}/3)`
    }
  };
} else {
  // Marcar como failed
  return {
    json: {
      id: reminderId,
      action: 'failed',
      attempts: attempts,
      error_message: `${errorMessage} (falhou ap├│s 3 tentativas)`
    }
  };
}

